            pollFunc: ffi_botho_mobile_rust_future_poll_rust_buffer,
            completeFunc: ffi_botho_mobile_rust_future_complete_rust_buffer,
            freeFunc: ffi_botho_mobile_rust_future_free_rust_buffer,
            liftFunc: FfiConverterSequenceTypeTransactionEntry.lift,
            errorHandler: FfiConverterTypeMobileWalletError.lift
        )
}
    
    /**
     * Lock the wallet and securely zeroize keys
     */
open func lock()async  -> Bool {
    return
        try!  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_botho_mobile_fn_method_mobilewallet_lock(
                    self.uniffiClonePointer()
                    
                )
            },
            pollFunc: ffi_botho_mobile_rust_future_poll_i8,
            completeFunc: ffi_botho_mobile_rust_future_complete_i8,
            freeFunc: ffi_botho_mobile_rust_future_free_i8,
            liftFunc: FfiConverterBool.lift,
            errorHandler: nil
            
        )
}
    
    /**
     * Request testnet coins from the faucet for this wallet's address.
     *
     * Calls the configured node's `faucet_request` RPC with this wallet's
     * address. (Point `set_node_url` at the faucet node, e.g.
     * `https://faucet.botho.io`.)
     */
open func requestFaucet()async throws  -> FaucetResult {
    return
        try  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_botho_mobile_fn_method_mobilewallet_request_faucet(
                    self.uniffiClonePointer()
                    
                )
            },
            pollFunc: ffi_botho_mobile_rust_future_poll_rust_buffer,
            completeFunc: ffi_botho_mobile_rust_future_complete_rust_buffer,
            freeFunc: ffi_botho_mobile_rust_future_free_rust_buffer,
            liftFunc: FfiConverterTypeFaucetResult.lift,
            errorHandler: FfiConverterTypeMobileWalletError.lift
        )
}
    
    /**
     * Send a transfer of `amount_picocredits` to `to_address`.
     *
     * `to_address` must be a testnet address (`tbotho://1/<base58>`) or the
     * legacy `view:<hex>,spend:<hex>` form. Syncs, builds a node-valid CLSAG
     * transaction from the wallet's spendable outputs, submits it, and returns
     * the transaction hash.
     */
open func sendTransaction(toAddress: String, amountPicocredits: UInt64)async throws  -> String {
    return
        try  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_botho_mobile_fn_method_mobilewallet_send_transaction(
                    self.uniffiClonePointer(),
                    FfiConverterString.lower(toAddress),FfiConverterUInt64.lower(amountPicocredits)
                )
            },
            pollFunc: ffi_botho_mobile_rust_future_poll_rust_buffer,
            completeFunc: ffi_botho_mobile_rust_future_complete_rust_buffer,
            freeFunc: ffi_botho_mobile_rust_future_free_rust_buffer,
            liftFunc: FfiConverterString.lift,
            errorHandler: FfiConverterTypeMobileWalletError.lift
        )
}
    
    /**
     * Set the node URL for RPC connections
     */
open func setNodeUrl(url: String)async  {
    return
        try!  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_botho_mobile_fn_method_mobilewallet_set_node_url(
                    self.uniffiClonePointer(),
                    FfiConverterString.lower(url)
                )
            },
            pollFunc: ffi_botho_mobile_rust_future_poll_void,
            completeFunc: ffi_botho_mobile_rust_future_complete_void,
            freeFunc: ffi_botho_mobile_rust_future_free_void,
            liftFunc: { $0 },
            errorHandler: nil
            
        )
}
    
    /**
     * Unlock wallet with mnemonic phrase
     *
     * The mnemonic is stored in secure memory and zeroized on lock.
     */
open func unlockWithMnemonic(mnemonic: String)async throws  -> WalletAddress {
    return
        try  await uniffiRustCallAsync(
            rustFutureFunc: {
