/**
 * Result of a faucet request
 */
public struct FaucetResult {
    /**
     * Whether the faucet dispensed coins
     */
    public var success: Bool
    /**
     * Transaction hash of the faucet payout (empty if unsuccessful)
     */
    public var txHash: String
    /**
     * Amount dispensed in picocredits
     */
    public var amount: UInt64
    /**
     * Human-readable amount (e.g. "10.000000 BTH")
     */
    public var amountFormatted: String
    /**
     * Optional message from the faucet (error or rate-limit info)
     */
    public var message: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Whether the faucet dispensed coins
         */success: Bool, 
        /**
         * Transaction hash of the faucet payout (empty if unsuccessful)
         */txHash: String, 
        /**
         * Amount dispensed in picocredits
         */amount: UInt64, 
        /**
         * Human-readable amount (e.g. "10.000000 BTH")
         */amountFormatted: String, 
        /**
         * Optional message from the faucet (error or rate-limit info)
         */message: String) {
        self.success = success
        self.txHash = txHash
        self.amount = amount
        self.amountFormatted = amountFormatted
        self.message = message
    }
}



extension FaucetResult: Equatable, Hashable {
    public static func ==(lhs: FaucetResult, rhs: FaucetResult) -> Bool {
        if lhs.success != rhs.success {
            return false
        }
        if lhs.txHash != rhs.txHash {
            return false
        }
        if lhs.amount != rhs.amount {
            return false
        }
        if lhs.amountFormatted != rhs.amountFormatted {
            return false
        }
        if lhs.message != rhs.message {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(success)
        hasher.combine(txHash)
        hasher.combine(amount)
        hasher.combine(amountFormatted)
        hasher.combine(message)
    }
}


