@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMobileWalletError: FfiConverterRustBuffer {
    typealias SwiftType = MobileWalletError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> MobileWalletError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .WalletLocked
        case 2: return .InvalidMnemonic
        case 3: return .InvalidPassword
        case 4: return .SessionExpired
        case 5: return .NetworkError(
            message: try FfiConverterString.read(from: &buf)
            )
        case 6: return .InvalidAddress
        case 7: return .InsufficientFunds
        case 8: return .InternalError(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: MobileWalletError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case .WalletLocked:
            writeInt(&buf, Int32(1))
        
        
        case .InvalidMnemonic:
            writeInt(&buf, Int32(2))
        
        
        case .InvalidPassword:
            writeInt(&buf, Int32(3))
        
        
        case .SessionExpired:
            writeInt(&buf, Int32(4))
        
        
        case let .NetworkError(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)
            
        
        case .InvalidAddress:
            writeInt(&buf, Int32(6))
        
        
        case .InsufficientFunds:
            writeInt(&buf, Int32(7))
        
        
        case let .InternalError(message):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


