#if swift(>=5.8)
@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterSequenceTypeTransactionEntry: FfiConverterRustBuffer {
    typealias SwiftType = [TransactionEntry]

    public static func write(_ value: [TransactionEntry], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterTypeTransactionEntry.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [TransactionEntry] {
        let len: Int32 = try readInt(&buf)
        var seq = [TransactionEntry]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeTransactionEntry.read(from: &buf))
        }
        return seq
    }
}
private let UNIFFI_RUST_FUTURE_POLL_READY: Int8 = 0
private let UNIFFI_RUST_FUTURE_POLL_MAYBE_READY: Int8 = 1

fileprivate let uniffiContinuationHandleMap = UniffiHandleMap<UnsafeContinuation<Int8, Never>>()

fileprivate func uniffiRustCallAsync<F, T>(
    rustFutureFunc: () -> UInt64,
    pollFunc: (UInt64, @escaping UniffiRustFutureContinuationCallback, UInt64) -> (),
    completeFunc: (UInt64, UnsafeMutablePointer<RustCallStatus>) -> F,
    freeFunc: (UInt64) -> (),
    liftFunc: (F) throws -> T,
    errorHandler: ((RustBuffer) throws -> Swift.Error)?
) async throws -> T {
    // Make sure to call uniffiEnsureInitialized() since future creation doesn't have a
    // RustCallStatus param, so doesn't use makeRustCall()
    uniffiEnsureInitialized()
    let rustFuture = rustFutureFunc()
    defer {
        freeFunc(rustFuture)
    }
    var pollResult: Int8;
    repeat {
        pollResult = await withUnsafeContinuation {
            pollFunc(
                rustFuture,
                uniffiFutureContinuationCallback,
                uniffiContinuationHandleMap.insert(obj: $0)
            )
        }
    } while pollResult != UNIFFI_RUST_FUTURE_POLL_READY

    return try liftFunc(makeRustCall(
        { completeFunc(rustFuture, $0) },
        errorHandler: errorHandler
    ))
}

// Callback handlers for an async calls.  These are invoked by Rust when the future is ready.  They
// lift the return value or error and resume the suspended function.
fileprivate func uniffiFutureContinuationCallback(handle: UInt64, pollResult: Int8) {
    if let continuation = try? uniffiContinuationHandleMap.remove(handle: handle) {
        continuation.resume(returning: pollResult)
    } else {
        print("uniffiFutureContinuationCallback invalid handle")
    }
}

private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private var initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 26
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_botho_mobile_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_generate_wallet() != 41380) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_get_address() != 6885) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_get_balance() != 65032) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_get_node_status() != 28927) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_get_session_status() != 34409) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_get_transaction_history() != 12335) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_lock() != 29855) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_request_faucet() != 41345) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_send_transaction() != 55526) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_set_node_url() != 57649) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_method_mobilewallet_unlock_with_mnemonic() != 46611) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_botho_mobile_checksum_constructor_mobilewallet_new() != 30544) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

private func uniffiEnsureInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

